const EXPORT_MODEL = [
  { export: 'DATA', source: 'DATA E HORA INÍCIO EXECUÇÃO', transform: 'date' },
  { export: 'PDV', source: 'PDV' },
  { export: 'PROMOTOR', source: 'PROMOTOR' },
  { export: 'ITENS', source: 'SKU' },
  { export: 'RUPTURA TOTAL?', source: 'RUPTURA TOTAL?' },
  { export: 'PRODUTO EM RUPTURA?', source: 'PRODUTO EM RUPTURA?' },
  { export: 'PRECO', source: 'PRECO' },
  { export: 'QTD. UNIDADE NO ESTOQUE', source: 'ESTOQUE TOTAL DA LOJA (UNIDADE)' },
  { export: 'TEM SKU VENCENDO EM 60 DIAS?', source: 'TEM SKU VENCENDO EM 60 DIAS?' },
  { export: 'DATA DO DIA', source: 'DATA E HORA INÍCIO EXECUÇÃO', transform: 'date' },
  { export: 'INFORME A VALIDADE', source: 'INFORME A VALIDADE' },
  { export: 'DIAS PARA O VENCIMENTO', source: 'DIAS PARA O VENCIMENTO' },
  { export: 'QUAL A QUANTIDADE EM UNIDADES?', source: 'QUAL A QUANTIDADE EM UNIDADES?' },
  { export: 'INFORME O LOTE', source: 'INFORME O LOTE' },
  { export: 'TEM UM SEGUNDO LOTE EM VENCIMENTO?', source: 'TEM UM SEGUNDO LOTE EM VENCIMENTO?' },
  { export: 'TEM PONTO EXTRA?', source: 'TEM PONTO EXTRA?' },
  { export: 'QUANTAS CAIXAS FORAM ABASTECIDAS?', source: 'QUANTAS CAIXAS FORAM ABASTECIDAS?' }
];

const state = {
  files: [],
  activeIndex: 0
};

// DOM Elements
const fileInput = document.getElementById('fileInput');
const dropzone = document.getElementById('dropzone');
const loadSampleBtn = document.getElementById('loadSampleBtn');
const mappingSection = document.getElementById('mappingSection');
const previewSection = document.getElementById('previewSection');
const mappingTableBody = document.getElementById('mappingTableBody');
const previewWrap = document.getElementById('previewWrap');
const countRows = document.getElementById('countRows');
const countColumns = document.getElementById('countColumns');
const downloadCsvBtn = document.getElementById('downloadCsvBtn');
const downloadExcelBtn = document.getElementById('downloadExcelBtn');
const loadingOverlay = document.getElementById('loadingOverlay');
const fileTabsContainer = document.querySelector('.file-tabs');

// Helper to show/hide loading
function toggleLoading(show) {
  if (show) {
    loadingOverlay.classList.remove('hidden');
  } else {
    loadingOverlay.classList.add('hidden');
  }
}

// Custom Alert with SweetAlert2 fallback
function showAlert(title, text, icon = 'info') {
  if (typeof Swal !== 'undefined') {
    Swal.fire({ title, text, icon, confirmButtonColor: '#f07f27' });
  } else {
    alert(`${title}\n\n${text}`);
  }
}

// Drag and Drop Events

dropzone.addEventListener('dragover', (e) => {
  e.preventDefault();
  dropzone.classList.add('dragover');
});

dropzone.addEventListener('dragleave', () => {
  dropzone.classList.remove('dragover');
});

dropzone.addEventListener('drop', (e) => {
  e.preventDefault();
  dropzone.classList.remove('dragover');
  const files = e.dataTransfer.files;
  if (files && files.length) handleFiles(files);
});

fileInput.addEventListener('change', (e) => {
  const files = e.target.files;
  if (files && files.length) handleFiles(files);
});

loadSampleBtn.addEventListener('click', async () => {
  toggleLoading(true);
  try {
    state.files = [];
    state.activeIndex = 0;
    const response = await fetch('sample-deluc.csv');
    const content = await response.text();

    setTimeout(() => {
      const processed = processCsv(content, "exemplo_deluc");
      if (processed) {
        state.files.push(processed);
        renderApp();
      }
      toggleLoading(false);
    }, 100);
  } catch (error) {
    toggleLoading(false);
    showAlert('Erro', 'Não foi possível carregar o exemplo localmente.', 'error');
  }
});

async function handleFiles(fileList) {
  const files = Array.from(fileList).filter(f => f.name.toLowerCase().endsWith('.csv'));
  if (files.length === 0) {
    showAlert('Aviso', 'Nenhum arquivo .CSV válido selecionado.', 'warning');
    return;
  }

  toggleLoading(true);
  state.files = [];
  state.activeIndex = 0;

  try {
    for (const file of files) {
      const content = await readFileAsText(file, 'windows-1252');
      const baseName = file.name.replace(/\.[^/.]+$/, "");
      const processed = processCsv(content, baseName);
      if (processed) {
        state.files.push(processed);
      }
    }

    if (state.files.length > 0) {
      renderApp();
    }
  } catch (e) {
    showAlert('Erro', 'Falha ao ler os arquivos selecionados.', 'error');
  } finally {
    toggleLoading(false);
  }
}

function readFileAsText(file, encoding) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = e => resolve(e.target.result);
    reader.onerror = e => reject(e);
    reader.readAsText(file, encoding);
  });
}

function renderApp() {
  if (state.files.length === 0) return;
  const activeFile = state.files[state.activeIndex];

  renderTabs();
  renderMapping(activeFile.columns);
  renderPreview(activeFile.columns, activeFile.rows);

  countRows.textContent = activeFile.rows.length;
  countColumns.textContent = activeFile.columns.length;

  mappingSection.classList.remove('hidden');
  previewSection.classList.remove('hidden');
}

function renderTabs() {
  if (!fileTabsContainer) return;
  fileTabsContainer.innerHTML = '';

  if (state.files.length <= 1) return;

  state.files.forEach((f, idx) => {
    const btn = document.createElement('button');
    btn.className = `tab-btn ${idx === state.activeIndex ? 'active' : ''}`;
    btn.textContent = f.originalFileName;
    btn.addEventListener('click', () => {
      state.activeIndex = idx;
      renderApp();
    });
    fileTabsContainer.appendChild(btn);
  });
}

// Download Handlers
downloadCsvBtn.addEventListener('click', async () => {
  if (!state.files.length) return;

  if (state.files.length === 1) {
    const activeFile = state.files[0];
    const csv = buildCsv(activeFile.columns, activeFile.rows);
    downloadFile(csv, `${activeFile.originalFileName}_final.csv`, 'text/csv;charset=utf-8;');
  } else {
    toggleLoading(true);
    try {
      const zip = new JSZip();
      for (const file of state.files) {
        const csv = buildCsv(file.columns, file.rows);
        zip.file(`${file.originalFileName}_final.csv`, csv);
      }
      const zipContent = await zip.generateAsync({ type: 'blob' });
      const url = URL.createObjectURL(zipContent);
      const a = document.createElement('a');
      a.href = url;
      a.download = 'Relatorios_CSV_Final.zip';
      document.body.appendChild(a);
      a.click();
      a.remove();
      URL.revokeObjectURL(url);
    } catch (e) {
      showAlert('Erro', 'Falha ao criar o arquivo ZIP (CSV).', 'error');
    }
    toggleLoading(false);
  }
});

downloadExcelBtn.addEventListener('click', async () => {
  if (!state.files.length) return;

  try {
    toggleLoading(true);

    // 1. Extrair Lógo em String (Aqui o usuário pode colar sua Base64 em vez dessa branca de teste)
    // DICA: Use um site como base64-image.de para jogar seu png e pegar o código gigantesco
    const LOGO_BASE64 = "data:image/png;base64,";

    const generateExcelBlob = async (fileObj) => {
      // 2. Calcular DATA Mínima e Máxima para o Nome do Arquivo - à prova de erros cross-format
      let minDate = null;
      let maxDate = null;

      fileObj.rows.forEach(row => {
        let dateStr = row['DATA DO DIA'];
        if (!dateStr) {
          const dataFull = row['DATA'];
          if (dataFull) dateStr = dataFull.split(' ')[0];
        }

        if (dateStr) {
          let d = null;
          if (dateStr.includes('/')) {
            const p = dateStr.split('/');
            // DD/MM/YYYY
            if (p.length === 3) d = new Date(Number(p[2]), Number(p[1]) - 1, Number(p[0]));
          } else if (dateStr.includes('-')) {
            const p = dateStr.split('-');
            // YYYY-MM-DD
            if (p.length === 3) d = new Date(Number(p[0]), Number(p[1]) - 1, Number(p[2]));
          }

          if (d && !isNaN(d.getTime())) {
            if (!minDate || d < minDate) minDate = d;
            if (!maxDate || d > maxDate) maxDate = d;
          }
        }
      });

      const formatDt = (d) => {
        if (!d) return '';
        return `${String(d.getDate()).padStart(2, '0')}/${String(d.getMonth() + 1).padStart(2, '0')}/${d.getFullYear()}`;
      };

      let dateRangeStr = '';
      if (minDate && maxDate) {
        const minStr = formatDt(minDate);
        const maxStr = formatDt(maxDate);
        dateRangeStr = minStr === maxStr ? minStr : `${minStr} a ${maxStr}`;
      }

      let baseName = fileObj.originalFileName ? fileObj.originalFileName : 'Relatório Exportado';

      // Filtro 1: Limpar numeradores de download duplicado do Windows ex: "arquivo (1)"
      baseName = baseName.replace(/\s*\(\d+\)$/, '');

      // Filtro 2: Pegar rigorosamente apenas o que vem DENTRO/APÓS da palavra Pesquisa
      let cleanName = baseName;
      const regexPesquisa = /^pesquisa[_\-\s]*/i;
      if (regexPesquisa.test(baseName)) {
        cleanName = baseName.replace(regexPesquisa, '');
      }

      const finalFileName = dateRangeStr ? `${cleanName} - ${dateRangeStr.replace(/\//g, '.')}.xlsx` : `${cleanName}.xlsx`;

      // 3. Montar Arquivo via ExcelJS
      const wb = new ExcelJS.Workbook();
      const ws = wb.addWorksheet('Relatório Semanal', {
        views: [{ showGridLines: false }]
      });

      // Subir logo na célula
      const imageId = wb.addImage({
        base64: LOGO_BASE64,
        extension: 'png',
      });

      // Configurar Alturas Padrões para Linhas 1 a 7 (Atuando como bloco de cabeçalho)
      for (let i = 1; i <= 7; i++) {
        ws.getRow(i).height = 20;
      }

      // Mesclar A1 até C7 para área da logo (Espaço de sobra para centrar)
      ws.mergeCells(1, 1, 7, 3);
      ws.addImage(imageId, {
        tl: { col: 0.2, row: 0.8 },
        ext: { width: 174, height: 100 } // Equivalente a 4.61cm largura x 2.65cm altura
      });

      // Mesclar Celulas do título gigante (D1 ate o final das colunas usadas, entre as linhas 1 e 7)
      const endColIndex = Math.max(fileObj.columns.length, 6);
      ws.mergeCells(1, 4, 7, endColIndex);

      // Escrever Título no Estilo da Foto (RichText para Multiplos Tamanhos)
      const titleCell = ws.getCell(1, 4);

      // Converte `RISSO` para `RELATÓRIO RISSO` (E substitui possiveis underscores que vieram do arquivo por espaços)
      const titleText = `RELATÓRIO ${cleanName.toUpperCase().replace(/_/g, ' ')}`;
      const dateText = "PERÍODO: " + dateRangeStr.toUpperCase();

      titleCell.value = {
        richText: [
          { text: titleText + '\n', font: { name: "Aptos Narrow", size: 16, bold: true, color: { argb: "FF000000" } } },
          { text: dateText, font: { name: "Aptos Narrow", size: 14, bold: true, color: { argb: "FF000000" } } }
        ]
      };
      titleCell.alignment = { horizontal: "left", vertical: "middle", wrapText: true };

      // Linha 8 = Colunas de Cabeçalho dos Dados
      const headerRow = ws.getRow(8);
      fileObj.columns.forEach((colName, idx) => {
        const cell = headerRow.getCell(idx + 1);
        cell.value = colName;
        // Cor de fundo Sólida e Letras Brancas 
        cell.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FFF07F27' } };
        cell.font = { name: "Aptos Narrow", size: 10, bold: true, color: { argb: "FFFFFFFF" } };
        cell.alignment = { horizontal: "center", vertical: "middle" };
        cell.border = {
          top: { style: 'thin', color: { argb: "FF000000" } }, right: { style: 'thin', color: { argb: "FF000000" } },
          bottom: { style: 'thin', color: { argb: "FF000000" } }, left: { style: 'thin', color: { argb: "FF000000" } }
        };
      });

      // Escrever Dados Intercalados na Linha 9 em diante
      fileObj.rows.forEach((row, rowIdx) => {
        const dbRow = ws.getRow(rowIdx + 9);
        const isOdd = rowIdx % 2 !== 0;
        const bgColor = isOdd ? 'FFFDF2E9' : 'FFFFFFFF';

        fileObj.columns.forEach((colName, colIdx) => {
          const cell = dbRow.getCell(colIdx + 1);
          cell.value = row[colName] ?? '';
          cell.font = { name: "Aptos Narrow", size: 10, color: { argb: "FF000000" } };
          cell.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: bgColor } };
          cell.alignment = { horizontal: "center", vertical: "middle", wrapText: true };
          cell.border = {
            top: { style: 'thin', color: { argb: "FF000000" } }, right: { style: 'thin', color: { argb: "FF000000" } },
            bottom: { style: 'thin', color: { argb: "FF000000" } }, left: { style: 'thin', color: { argb: "FF000000" } }
          };
        });
      });

      // Auto Filtros nas Colunas 
      ws.autoFilter = {
        from: { row: 8, column: 1 },
        to: { row: fileObj.rows.length + 8, column: fileObj.columns.length }
      };

      // AutoAjuste Largura das Colunas
      fileObj.columns.forEach((colName, idx) => {
        let maxLen = colName.length + 5;
        for (let r = 0; r < Math.min(50, fileObj.rows.length); r++) {
          const val = String(fileObj.rows[r][colName] ?? '');
          if (val.length > maxLen) maxLen = val.length;
        }
        ws.getColumn(idx + 1).width = Math.min(maxLen + 2, 60);
      });

      // Exportação em formato Buffer compatível com FileSaver nativo via Blob
      const buffer = await wb.xlsx.writeBuffer();
      const blob = new Blob([buffer], { type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' });
      return { blob, fileName: finalFileName };
    };

    if (state.files.length === 1) {
      const { blob, fileName } = await generateExcelBlob(state.files[0]);
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = fileName;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      window.URL.revokeObjectURL(url);
    } else {
      const zip = new JSZip();
      for (const f of state.files) {
        const { blob, fileName } = await generateExcelBlob(f);
        zip.file(fileName, blob);
      }
      const zipContent = await zip.generateAsync({ type: 'blob' });
      const url = window.URL.createObjectURL(zipContent);
      const a = document.createElement('a');
      a.href = url;
      a.download = 'Relatorios_Excel_Final.zip';
      document.body.appendChild(a);
      a.click();
      a.remove();
      window.URL.revokeObjectURL(url);
    }

    toggleLoading(false);

  } catch (e) {
    toggleLoading(false);
    showAlert('Erro', 'Houve um problema ao gerar o arquivo Excel formatado. Verifique os dados.', 'error');
    console.error(e);
  }
});

function processCsv(content, originalFileName) {
  const parsed = parseDelimitedCsv(content, ';');
  if (parsed.length < 2) {
    showAlert('Erro', 'O arquivo possui muito poucas linhas ou não está no formato delimitado por ";".', 'error');
    return null;
  }

  const headers = parsed[1].map((value) => normalizeHeader(value));

  // Sanity Check: Verifica se pelo menos alguma das colunas esperadas existe
  const expectedSources = EXPORT_MODEL.map(m => normalizeHeader(m.source));
  const foundRequired = expectedSources.some(src => headers.includes(src));

  if (!foundRequired) {
    showAlert('Aviso de Incompatibilidade', 'Não encontramos as colunas padrões da Pesquisa Deluc neste arquivo. O relatório gerado pode conter dados inconsistentes ou completamente vazios.', 'warning');
  }

  const body = parsed.slice(2).filter((row) => row.some((cell) => String(cell || '').trim() !== ''));

  const transformed = body.map((row) => {
    const obj = {};

    for (const rule of EXPORT_MODEL) {
      const sourceIndex = headers.indexOf(normalizeHeader(rule.source));
      const rawValue = sourceIndex >= 0 ? String(row[sourceIndex] ?? '').trim() : '';
      obj[rule.export] = applyTransform(rawValue, rule.transform);
    }

    return obj;
  });

  const exportColumns = EXPORT_MODEL
    .map((item) => item.export)
    .filter((col) => transformed.some((row) => String(row[col] ?? '').trim() !== ''));

  return { originalFileName, rows: transformed, columns: exportColumns };
}

function normalizeHeader(value) {
  return String(value || '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/\s+/g, ' ')
    .trim()
    .toUpperCase();
}

function applyTransform(value, transform) {
  if (!value) return '';
  if (transform === 'date' || transform === 'datetime') {
    let dateStr = value.split(' ')[0] || '';
    if (dateStr.includes('-')) {
      const p = dateStr.split('-');
      if (p.length === 3) return `${p[2]}/${p[1]}/${p[0]}`;
    }
    return dateStr;
  }
  return value;
}

function parseDelimitedCsv(text, delimiter) {
  const rows = [];
  let current = [];
  let field = '';
  let inQuotes = false;

  for (let i = 0; i < text.length; i++) {
    const char = text[i];
    const next = text[i + 1];

    if (char === '"') {
      if (inQuotes && next === '"') {
        field += '"';
        i++;
      } else {
        inQuotes = !inQuotes;
      }
      continue;
    }

    if (char === delimiter && !inQuotes) {
      current.push(field);
      field = '';
      continue;
    }

    if ((char === '\n' || char === '\r') && !inQuotes) {
      if (char === '\r' && next === '\n') i++;
      current.push(field);
      rows.push(current);
      current = [];
      field = '';
      continue;
    }

    field += char;
  }

  if (field.length || current.length) {
    current.push(field);
    rows.push(current);
  }

  return rows;
}

function renderMapping(exportColumns) {
  mappingTableBody.innerHTML = '';
  EXPORT_MODEL.filter(item => exportColumns.includes(item.export)).forEach((item) => {
    const tr = document.createElement('tr');
    tr.innerHTML = `
      <td><strong>${escapeHtml(item.export)}</strong></td>
      <td>${item.transform === 'date'
        ? `<span class="badge">Sintetizada de</span> ${escapeHtml(item.source)}`
        : escapeHtml(item.source)}</td>
    `;
    mappingTableBody.appendChild(tr);
  });
}

function renderPreview(columns, rows) {
  const table = document.createElement('table');
  const thead = document.createElement('thead');
  const tbody = document.createElement('tbody');

  thead.innerHTML = `<tr>${columns.map(col => `<th>${escapeHtml(col)}</th>`).join('')}</tr>`;
  rows.slice(0, 200).forEach((row) => {
    const tr = document.createElement('tr');
    tr.innerHTML = columns.map((col) => `<td>${escapeHtml(row[col] ?? '')}</td>`).join('');
    tbody.appendChild(tr);
  });

  table.appendChild(thead);
  table.appendChild(tbody);

  previewWrap.innerHTML = '';
  previewWrap.appendChild(table);
}

function buildCsv(columns, rows) {
  const lines = [columns.join(';')];
  for (const row of rows) {
    const values = columns.map((col) => csvEscape(row[col] ?? ''));
    lines.push(values.join(';'));
  }
  return '\uFEFF' + lines.join('\r\n');
}

function csvEscape(value) {
  const text = String(value ?? '');
  if (/[";\n\r]/.test(text)) return `"${text.replace(/"/g, '""')}"`;
  return text;
}

function escapeHtml(value) {
  return String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
}

function downloadFile(content, fileName, mimeType) {
  const blob = new Blob([content], { type: mimeType });
  const url = URL.createObjectURL(blob);
  const link = document.createElement('a');
  link.href = url;
  link.download = fileName;
  document.body.appendChild(link);
  link.click();
  link.remove();
  URL.revokeObjectURL(url);
}
